// Generated by claude-internal tools.

const P = window.__PREFIX__ || '';
const BAR_COLORS = ['#e74c3c','#e67e22','#f39c12','#f1c40f','#2ecc71','#1abc9c','#3498db','#9b59b6','#34495e','#95a5a6'];

document.addEventListener('DOMContentLoaded', () => {
    loadDashboard();
});

async function loadDashboard() {
    try {
        const res = await fetch(P + '/api/dashboard');
        const data = await res.json();
        renderMonthlySummary(data);
        renderYearlySummary(data);
        renderTop10Section('top10MonthlySection', `本月 Top 10 消费 (${data.monthly.period})`, data.top10_monthly, data.cards);
        renderTop10Section('top10YearlySection', `本年 Top 10 消费 (${data.yearly.period})`, data.top10_yearly, data.cards);
        renderRecentByCard(data.recent_by_card, data.cards);
    } catch (e) {
        console.error('Failed to load dashboard:', e);
    }
}

function renderMonthlySummary(data) {
    const el = document.getElementById('monthlySummary');
    const m = data.monthly;
    let html = '';

    for (const card of data.cards) {
        const info = m.by_card[card] || { total: 0, count: 0 };
        html += `<div class="amount-row">
            <span class="label">卡 ${card}</span>
            <span><span class="value">${formatMoney(info.total)}</span><span class="count">${info.count}笔</span></span>
        </div>`;
    }

    html += `<div class="amount-row">
        <span class="label">合计 (${m.period})</span>
        <span><span class="value total">${formatMoney(m.total)}</span><span class="count">${m.count}笔</span></span>
    </div>`;

    el.innerHTML = html;
    el.closest('.card').classList.remove('loading');
}

function renderYearlySummary(data) {
    const el = document.getElementById('yearlySummary');
    const y = data.yearly;
    let html = '';

    for (const card of data.cards) {
        const info = y.by_card[card] || { total: 0, count: 0 };
        html += `<div class="amount-row">
            <span class="label">卡 ${card}</span>
            <span><span class="value">${formatMoney(info.total)}</span><span class="count">${info.count}笔</span></span>
        </div>`;
    }

    html += `<div class="amount-row">
        <span class="label">合计 (${y.period})</span>
        <span><span class="value total">${formatMoney(y.total)}</span><span class="count">${y.count}笔</span></span>
    </div>`;

    el.innerHTML = html;
    el.closest('.card').classList.remove('loading');
}

function renderTop10Section(containerId, title, top10Data, cards) {
    const container = document.getElementById(containerId);
    if (!top10Data || cards.length === 0) {
        container.innerHTML = '';
        return;
    }

    // Render cards side by side
    let html = `<div class="top10-section"><h3 class="section-title">${title}</h3><div class="top10-grid">`;

    for (const card of cards) {
        const items = top10Data[card] || [];
        html += `<div class="card top10-card">
            <h3>卡 ${card}</h3>`;

        if (items.length === 0) {
            html += '<p class="loading-text">暂无数据</p>';
        } else {
            const maxAmount = items[0].amount; // already sorted DESC
            html += '<div class="top10-list">';
            items.forEach((item, idx) => {
                const pct = maxAmount > 0 ? (item.amount / maxAmount * 100) : 0;
                const color = BAR_COLORS[idx % BAR_COLORS.length];
                html += `
                <div class="top10-item">
                    <div class="top10-rank">${idx + 1}</div>
                    <div class="top10-info">
                        <div class="top10-header">
                            <span class="top10-merchant" title="${item.merchant}">${item.merchant}</span>
                            <span class="top10-amount">${formatMoney(item.amount)}</span>
                        </div>
                        <div class="top10-bar-bg">
                            <div class="top10-bar" style="width:${pct}%;background:${color};"></div>
                        </div>
                        <div class="top10-meta">
                            <span class="badge badge-info">${item.category}</span>
                            <span class="top10-date">${item.trans_date}</span>
                        </div>
                    </div>
                </div>`;
            });
            html += '</div>';
        }

        html += '</div>';
    }

    html += '</div></div>';
    container.innerHTML = html;
}

function renderRecentByCard(recentByCard, cards) {
    const grid = document.getElementById('recentGrid');
    if (!recentByCard || cards.length === 0) {
        grid.innerHTML = '<p class="loading-text">暂无交易数据，请先在数据管理页面抓取数据</p>';
        return;
    }

    let html = '';
    for (const card of cards) {
        const transactions = recentByCard[card] || [];
        html += `<div class="card">
            <h3>卡 ${card}</h3>`;

        if (transactions.length === 0) {
            html += '<p class="loading-text">暂无数据</p>';
        } else {
            html += `<div class="table-wrapper"><table>
                <thead><tr><th>日期</th><th>商户</th><th>分类</th><th>金额</th></tr></thead><tbody>`;
            for (const t of transactions) {
                const refStyle = t.refunded ? ' style="opacity:0.45;text-decoration:line-through;"' : '';
                const refBadge = t.refunded ? ' <span class="badge badge-danger">已退货</span>' : '';
                html += `<tr${refStyle}>
                    <td>${t.trans_date}</td>
                    <td>${t.merchant}${refBadge}</td>
                    <td><span class="badge badge-info">${t.category}</span></td>
                    <td style="font-weight:600;color:${t.refunded ? '#999' : '#e74c3c'}">${formatMoney(t.amount)}</td>
                </tr>`;
            }
            html += '</tbody></table></div>';
        }

        html += '</div>';
    }

    grid.innerHTML = html;
}

function formatMoney(amount) {
    return '¥' + Number(amount).toLocaleString('zh-CN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}
